syntax = "proto3";

service OrderService {
  rpc PlaceOrder (PlaceOrderRequest) returns (PlaceOrderResponse);
  rpc WatchOrder  (WatchOrderRequest)  returns (stream OrderEvent);
}

message PlaceOrderRequest {
  string product_id = 1;
  int32  quantity   = 2;
}

message PlaceOrderResponse {
  string order_id = 1;
  string status   = 2;
}

syntax = "proto3";

message User {
  uint64 id         = 1;
  string email      = 2;
  string given_name = 3;
  Role   role       = 4;
}

enum Role {
  ROLE_UNSPECIFIED = 0;
  ROLE_VIEWER      = 1;
  ROLE_EDITOR      = 2;
  ROLE_ADMIN       = 3;
}

import { createClient } from "@connectrpc/connect";
import { createConnectTransport } from "@connectrpc/connect-web";
import { OrderService } from "./gen/order_connect";

const transport = createConnectTransport({
  baseUrl: "https://api.example.com",
});

const client = createClient(OrderService, transport);

const response = await client.placeOrder({
  productId: "prod_42",
  quantity: 2,
});
console.log(response.orderId);

query GetUser($id: ID!) {
  user(id: $id) {
    id
    email
    profile {
      displayName
      avatarUrl
    }
    recentOrders(last: 3) {
      id
      total
      status
    }
  }
}

const resolvers = {
  Query: {
    user: async (_parent, { id }, ctx) => {
      return ctx.db.users.findById(id);
    },
  },
  User: {
    orders: async (user, _args, ctx) => {
      return ctx.db.orders.findByUserId(user.id);
    },
    orderCount: async (user, _args, ctx) => {
      return ctx.redis.get(`order-count:${user.id}`);
    },
  },
};

# Query that triggers the N+1 problem
query {
  users {          # 1 query — returns 100 users
    id
    email
    latestOrder {  # 100 queries — one per user!
      id
      total
    }
  }
}

# Fix: batch with DataLoader so latestOrder fires 1 query for all 100 user IDs

import DataLoader from "dataloader";
import { db } from "./db";

// Created fresh per request in Apollo context
export function createLoaders() {
  return {
    userById: new DataLoader(async (ids: readonly string[]) => {
      const users = await db.users.findManyByIds(ids);
      // Must return results in the same order as ids
      return ids.map(id => users.find(u => u.id === id) ?? null);
    }),
  };
}

subscription OnOrderUpdated($orderId: ID!) {
  orderUpdated(orderId: $orderId) {
    id
    status
    estimatedDelivery
    lineItems {
      productName
      quantity
    }
  }
}

import { OrderServiceClient } from "./gen/order_grpc_web_pb";
import { PlaceOrderRequest } from "./gen/order_pb";

const client = new OrderServiceClient("https://api.example.com");

const req = new PlaceOrderRequest();
req.setProductId("prod_42");
req.setQuantity(2);

client.placeOrder(req, {}, (err, response) => {
  if (err) throw err;
  console.log("Order ID:", response.getOrderId());
});

mutation PlaceOrder($input: PlaceOrderInput!) {
  placeOrder(input: $input) {
    ... on Order {
      id
      status
      estimatedDelivery
    }
    ... on InsufficientFundsError {
      message
      shortfall
    }
    ... on OutOfStockError {
      message
      productId
    }
  }
}

